fn agent_phase2_execution_fee(iterations: u16, tool_calls: u16) -> U256 {
    U256::from(SOVEREIGN_AGENT_ITERATION_FEE_WEI) * U256::from(iterations) +
        U256::from(SOVEREIGN_AGENT_TOOL_CALL_FEE_WEI) * U256::from(tool_calls)
}

pub fn calculate_agent_fees_phase2_work(iterations: u16, tool_calls: u16) -> AsyncFees {
    AsyncFees::new(agent_phase2_execution_fee(iterations, tool_calls), U256::ZERO, U256::ZERO)
}
